import { Chess } from 'https://cdn.jsdelivr.net/npm/chess.js@1/+esm';
const chess = new Chess();
if ((data.notation_type ?? 'fen') === 'pgn') chess.loadPgn(data.notation, { strict: data.strict ?? false });
else chess.load(data.notation);
for (const ply of data.plies ?? []) chess.move(ply, { strict: data.strict ?? false });
const result = { fen: chess.fen(), pgn: chess.pgn(), legalMoves: chess.moves({ verbose: data.verbose_moves ?? false }), turn: chess.turn(), inCheck: chess.inCheck(), isCheckmate: chess.isCheckmate(), isStalemate: chess.isStalemate(), isDraw: chess.isDraw(), isGameOver: chess.isGameOver() };
